ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN CID COMMENT 'Customer ID - platform-internal primary key. From CustomerStatic. Used as the universal customer identifier across all tables. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
