ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN CountryID COMMENT 'Country of residence. From CustomerStatic. FK to Dictionary.Country. Determines regulatory framework, available instruments, and leverage limits. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
