ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN LanguageID COMMENT 'Customer''s preferred platform language. From CustomerStatic. FK to Dictionary.Language. Controls UI language. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN CommunicationLanguageID COMMENT 'Language for customer communications (emails, notifications). From CustomerStatic. May differ from LanguageID. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN CurrencyID COMMENT 'Customer''s account base currency. From CustomerStatic. FK to Dictionary.Currency (1=USD). Currently all USD in practice; central to the multi-currency migration roadmap. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN TimeZoneID COMMENT 'Customer''s time zone. From CustomerStatic. FK to Dictionary.TimeZone. Used for time-aware notifications. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN PlayerStatusID COMMENT 'Compliance and trading account status. From CustomerStatic. FK to Dictionary.PlayerStatus. 1=Active (97.5%); other values indicate restricted, closed, banned, or special states. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN CampaignID COMMENT 'Marketing campaign ID under which the customer was acquired. From CustomerStatic. FK to BackOffice.Campaign. NULL for organically acquired customers. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN PlayerLevelID COMMENT 'Customer experience/permission level. From CustomerStatic. FK to Dictionary.PlayerLevel. 1=Standard (94%); 4=Popular Investor (triggers IsHedged=0); 7=VIP. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN TradeLevelID COMMENT 'Trading knowledge/experience classification. From CustomerStatic. FK to Dictionary.TradeLevel. Used for MiFID suitability assessment. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN SpreadGroupID COMMENT 'Spread/pricing group. From CustomerStatic. FK to Trade.SpreadGroup. Determines which pricing table the customer uses. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN LabelID COMMENT 'Internal segment label. From CustomerStatic. FK to Dictionary.Label. LabelID=26 = BonusOnly (triggers IsHedged=0). (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN FunnelID COMMENT 'Registration funnel ID. From CustomerStatic. FK to Dictionary.Funnel. Tracks which user journey/funnel variant the customer came through. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN UserName COMMENT 'Customer''s login username. From CustomerStatic. Unique (case-insensitive). (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN Password COMMENT 'Hashed password. From CustomerStatic. varchar(20) stores a hash. Password changes are NOT versioned in History.Customer. Use Customer.CustomerSafty instead when password field should be hidden. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN Registered COMMENT 'Account registration date. From CustomerStatic. Default=getdate() at INSERT time. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN IsReal COMMENT 'Account type: 1=real-money account, 0=demo account. From CustomerStatic. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN IP COMMENT 'Registration IP address. From CustomerStatic. Dynamic Data Masking applied on the base table. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN Credit COMMENT 'Customer''s current available trading balance in USD. From CustomerMoney (LEFT JOIN). The core field updated by every financial transaction (deposit, withdrawal, position). NULL if no CustomerMoney row exists. See Customer.CustomerMoney for full balance write architecture. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN BirthDate COMMENT 'Customer date of birth. From CustomerStatic. Dynamic Data Masking on base table. Used in KYC age verification and duplicate detection (LinkedAccountHash1). (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN Gender COMMENT 'Gender: ''M'', ''F'', or ''U'' (Unknown). From CustomerStatic. CHECK constraint on base table. Used in duplicate detection hash. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN FirstName COMMENT 'Legal first name in Unicode. From CustomerStatic. Dynamic Data Masking on base table. nvarchar supports non-Latin scripts. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN LastName COMMENT 'Legal last name in Unicode. From CustomerStatic. Dynamic Data Masking on base table. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN MiddleName COMMENT 'Middle name in Unicode. From CustomerStatic. Dynamic Data Masking on base table. Added 2018 (changelog: 50094). (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN Address COMMENT 'Street address in Unicode. From CustomerStatic. Dynamic Data Masking on base table. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
