ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN SerialID COMMENT 'Affiliate (partner/introducing broker) ID. From CustomerStatic. FK to BackOffice.Affiliate. NULL for direct/organic registrations. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN ReferralID COMMENT 'Referral CID - the customer who referred this one. From CustomerStatic. Used for RAF (Refer-a-Friend) program tracking. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN SubSerialID COMMENT 'Sub-affiliate identifier string. From CustomerStatic. Up to 1024 chars for complex affiliate tracking paths. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN Email COMMENT 'Customer email address. From CustomerStatic. Dynamic Data Masking on base table. Unique (case-insensitive). (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN IsEmailVerified COMMENT 'Whether the email was verified by clicking a confirmation link. From CustomerStatic. NULL for accounts predating this flag. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN Phone COMMENT 'Primary phone number. From CustomerStatic. Dynamic Data Masking on base table. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN Fax COMMENT 'Fax number. From CustomerStatic. Legacy field; rarely populated in modern registrations. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN Mobile COMMENT 'Mobile number. From CustomerStatic. Dynamic Data Masking on base table. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN Comments COMMENT 'Internal comment field. From CustomerStatic. BackOffice operators can add notes. varchar(8000). (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN DownloadID COMMENT 'Platform download source ID. From CustomerStatic. Legacy tracking for which platform installer the customer used. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN BannerID COMMENT 'Advertising banner ID that led to registration. From CustomerStatic. Legacy acquisition tracking. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN ClientVersion COMMENT 'Client application version at registration. From CustomerStatic. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN PersonID COMMENT 'External person identifier. From CustomerStatic. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN BonusCredit COMMENT 'Promotional/bonus credits separate from real funds. From CustomerMoney (LEFT JOIN). NULL if no CustomerMoney row. Tracked separately to distinguish promotional funds from deposited funds. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN DownloadCounter COMMENT 'Number of times the customer has downloaded the platform client. From CustomerStatic. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN AccountExpirationDate COMMENT 'Expiration date for demo or time-limited accounts. From CustomerStatic. NULL for standard real-money accounts. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN HelpDeskType COMMENT 'Customer service tier assignment. From CustomerStatic. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN LotCountGroupID COMMENT 'Lot/quantity group. From CustomerStatic. FK to Dictionary.LotCountGroup. Controls min/max lot sizes for trading. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN PrivacyPolicyID COMMENT 'Privacy policy version accepted by the customer. From CustomerStatic. FK to Dictionary.PrivacyPolicy. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN GCID COMMENT 'Group Customer ID - cross-product identity key linking same person across eToro products. From CustomerStatic. NULL for accounts predating GCID introduction. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN WeekendFeePrecentage COMMENT 'Weekend swap fee percentage (100=full fee, <100=discounted). From CustomerStatic. Note: column name has typo "Precentage". (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN IsEmailActivated COMMENT 'Email activation status flag. From CustomerStatic. Separate from IsEmailVerified - tracks account email activation step completion. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN UserName_LOWER COMMENT 'Computed: lower(UserName). From CustomerStatic. Used for case-insensitive username uniqueness enforcement. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN RealizedEquity COMMENT 'Running total of realized account value (deposits + closed-position proceeds - withdrawals). From CustomerMoney (LEFT JOIN). NULL if no CustomerMoney row. Answers: "How much realized value does this customer have?" (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN AccountStatusID COMMENT 'Account operational status. From CustomerStatic. 1=Active/Normal (93.9%); 2=Closed/Restricted; NULL=pre-AccountStatusID era. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN PendingClosureStatusID COMMENT 'Status in the pending account closure workflow. From CustomerStatic. Default=1 (no pending closure). (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN IsRequestedCall COMMENT 'Whether the customer has requested a callback from sales/support. From CustomerStatic. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN FunnelFromID COMMENT 'Source funnel variant tracking within the acquisition funnel. From CustomerStatic. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN LeverageType COMMENT 'Leverage setting type (default=1). From CustomerStatic. Determines the leverage scheme applied to this account. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN TotalCash COMMENT 'Reconciled total cash balance maintained by the Trade.UpdateTotalCash reconciliation job. From CustomerMoney (LEFT JOIN). NULL if no CustomerMoney row. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN ClientTypeID COMMENT 'Client classification type for MiFID2 categorization (retail, professional, etc.). From CustomerStatic. FK to Dictionary.ClientType. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN IsHedged COMMENT 'Whether this customer''s trades are hedged on the broker side. From CustomerStatic. Managed by CustomerVersionInsert/Update triggers: 0 (not hedged) for Popular Investors (PlayerLevelID=4) or BonusOnly (LabelID=26) or CEP/BonusOnlyCustomers list members; 1 (hedged) for all others. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN LowerEmail COMMENT 'Computed: lower(Email). From CustomerStatic. Used for case-insensitive email uniqueness enforcement. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN ID COMMENT 'System GUID for REST API identity. From CustomerStatic. Default=newsequentialid(). Unique index on base table. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN VerificationTitle COMMENT 'KYC verification title/level text. From CustomerStatic. Default from Customer.VerificationTitle_Default() function. Changes are versioned in History.Customer. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN VerificationTitleVersion COMMENT 'Version GUID for optimistic concurrency on verification title updates. From CustomerStatic. Default=newid(). (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN BuildingNumber COMMENT 'Building/apartment number. From CustomerStatic. Dynamic Data Masking on base table. Structured address field added 2015 (changelog: 02/08/2015). (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN PhonePrefix COMMENT 'International dialing prefix (e.g., +1, +44). From CustomerStatic. Added 2015 (changelog: 27/10/2015). (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN PhoneBody COMMENT 'Local phone number without country prefix. From CustomerStatic. Dynamic Data Masking on base table. Added 2015 (changelog: 27/10/2015). (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN ExternalID COMMENT 'APEX broker external ID. From CustomerStatic. Unique index on base table. Decimal(38,0) accommodates APEX''s large numeric ID format. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN RegionID COMMENT 'Geographic region ID (GeoIP-derived or set). From CustomerStatic. Added 2016 (changelog: 40722) alongside CountryIDByIP for granular regulation. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN RegionByIP_ID COMMENT 'Region detected from IP address. From CustomerStatic. Added 2016 (changelog: 40722). Separate from RegionID (profile-based) for mismatch detection. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN PlatformID COMMENT 'Platform/product identifier (web, mobile, etc.). From CustomerStatic. Added 2016 (changelog: 40618). (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN BSLRealFunds COMMENT 'Real funds threshold for Balance Stop Loss (BSL) - safety floor that triggers position liquidation if equity drops below this level. From CustomerMoney (LEFT JOIN). NULL if no CustomerMoney row. Updated by PostMIMOOperations pipeline. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN OptOutReasonID COMMENT 'Reason for GDPR/marketing opt-out. From CustomerStatic. Added 2017 (changelog: 18-07-2017). (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN PlayerStatusReasonID COMMENT 'Reason code for current PlayerStatusID ("why" behind a non-Active status). From CustomerStatic. Added 2017 (changelog: 24/07/2017). (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN PlayerStatusSubReasonID COMMENT 'Sub-reason code for PlayerStatus (hierarchical). From CustomerStatic. FK to Dictionary.PlayerStatusSubReasons. Added 2019 (changelog: RD-1752). (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN PlayerStatusSubReasonComment COMMENT 'Free-text comment for the PlayerStatusSubReasonID. From CustomerStatic. Max 64 chars. Added 2019. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN POBCountryID COMMENT 'Place of birth country. From CustomerStatic. FK to Dictionary.Country. Added 2019 (HLD: RD-4436 Add Place of Birth to KYC). (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN SubRegionID COMMENT 'Sub-region (province/state for non-US countries). From CustomerStatic. FK to Dictionary.SubRegion. Added 2019 (changelog: 09/07/2019). (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN EmailVerificationProviderID COMMENT 'External email verification provider used for this customer''s email. From CustomerStatic. FK to Dictionary.EmailVerificationProvider. Added 2020. (Tier 1 - upstream wiki, etoro.Customer.Customer)';
ALTER TABLE main.pii_data.bronze_etoro_customer_customer ALTER COLUMN DltID COMMENT 'Distributed Ledger Technology integration ID. From CustomerStatic. Added per HLD: COAKVU-2880 DLT Integration. Links customer to DLT/blockchain system. (Tier 1 - upstream wiki, etoro.Customer.Customer)';

